{"name": "rand_int", "kind": "normal", "description": "返回区间 [min, max] 内的一个随机整数", "code": "import random

def rand_int(min: int, max: int) -> int:
    """返回区间 [min, max] 内的一个随机整数。

    Args:
        min: 区间下界（包含）
        max: 区间上界（包含）

    Returns:
        [min, max] 之间的随机整数
    """
    if min > max:
        raise ValueError(f"min ({min}) 不能大于 max ({max})")
    return random.randint(min, max)
"}

